head.script:
//-------------------------------------------------------------------------
// 화면내 hidden 컴포넌트 선언
//-------------------------------------------------------------------------
scwin.txt_sumAmtAll = "";
scwin.txt_susRecvSellAmtTot = 0;	    //<!-- 가수금매출금액+가수금매출환불차변금액 -->
scwin.txt_susRecvSellAmt = 0;	    //<!-- 가수금매출금액 -->
scwin.txt_susRecvSellRtnDrAmt = 0;	//<!-- 가수금매출환불차변금액 -->
scwin.hid_summary = "";
scwin.hid_goods = "";

//-------------------------------------------------------------------------
// 호출페이지 파라미터 
//-------------------------------------------------------------------------
scwin.param = "";

//-------------------------------------------------------------------------
// 호출 페이지별 파라미터 체크 , 모화면과 데이터전송방식 & 파라미터 명칭 맞는지 확인 필요
//-------------------------------------------------------------------------
scwin.blno = "";
scwin.intendDt = "";
scwin.kcomcd = "";
scwin.prtnGrpNo = "";
scwin.seaair = "";
scwin.iogb = "";
scwin.bilgClntNo = "";
scwin.userId = "";
scwin.type = "";
scwin.rmk = "";
scwin.remark = "";
scwin.eng = "";
scwin.locPtnCls = "";
scwin.pic = "";
scwin.summary = "";




//-------------------------------------------------------------------------
// 프로그램 전역 변수
//-------------------------------------------------------------------------
scwin.saveflag = "FALSE"; // 저장상태구분
scwin.bilgAmt = 0;
scwin.bilgAmtFcrc = 0;
scwin.fcrcBilgAmt = 0;

scwin.sumAmtAll = 0;			//매출합계금액
scwin.cashSellAmt = 0;		//현금매출액 		
scwin.susRecvSellRtnDrAmt = 0;//가수금매출환불차변금액
scwin.susRecvSellAmt = 0;		//가수금매출금액
scwin.susRecvSellAmtTot = 0;	//가수금매출금액+가수금매출환불차변금액
scwin.cashRtnAmt = 0;			//현금환불금액
scwin.clntMgntYn = 0;

scwin.susRecvInitamtClsCd = "01";
scwin.offsetNo1 = ""; 		//역분개 여부

scwin.strCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.strFrDate = WebSquare.date.dateAdd(scwin.strCurDate, -30);



//-------------------------------------------------------------------------
// 페이지 로드시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.param = $c.data.getParameter();
    scwin.blno = scwin.param.blno == null ? "" : scwin.param.blno;
    //Billing Date = 공급일자
    scwin.intendDt = scwin.param.intendDt == null ? "" : scwin.param.intendDt;
    //kcomcd
    scwin.kcomcd = scwin.param.kcomcd == null ? "" : scwin.param.kcomcd;
    //Invoice No
    scwin.prtnGrpNo = scwin.param.prtnGrpNo == null ? "" : scwin.param.prtnGrpNo;
    //sea:S,air:A
    scwin.seaair = scwin.param.seaair == null ? "" : scwin.param.seaair;
    //out:O,in:I
    scwin.iogb = scwin.param.iogb == null ? "" : scwin.param.iogb;
    //청구거래처코드
    scwin.bilgClntNo = scwin.param.bilgClntNo == null ? "" : scwin.param.bilgClntNo;
    //생성자
    scwin.userId = scwin.param.userId == null ? "" : scwin.param.userId;
    //Print Option
    scwin.type = scwin.param.type == null ? "" : scwin.param.type;
    //Remark 표시여부
    scwin.rmk = scwin.param.rmk == null ? "" : scwin.param.rmk;
    //Remark 
    scwin.remark = scwin.param.remark == null ? "" : scwin.param.remark;
    //Kor,Eng 
    scwin.eng = scwin.param.eng == null ? "" : scwin.param.eng;
    //1.Invoice, 2.Partner
    scwin.locPtnCls = scwin.param.locPtnCls == null ? "" : scwin.param.locPtnCls;
    //담당자 
    scwin.pic = scwin.param.pic == null ? "" : scwin.param.pic;

    scwin.summary = scwin.param.summary == null ? "" : scwin.param.summary;


    //let dataColumn = ["certiNo", 	"oldCertiNo",	"offsetNo1",	"sellVatNo",	"slipNo",	"certiPatternCd",	"bilgLodeptCd",	"bilgLodeptNm",	"bilgClntNo",	"bilgClntNm",	"taxnClsCd",	"taxnClsNm",	"receptClsCd",	"adptExchRt",	"exchRtAdptDt",	"adptExchRtInscrpYn",	"prebilgYn",	"pgmId",	"lineCd",	"vsslCd",	"portcnt",	"arDepPortDt",	"mrn",	"msn",	"hsn",	"blNo",	"packCnt",	"packUnitCd",	"totWt",	"totCbm",	"cntWtCbm",	"assgnBondZoneNm",	"billCoverPatternSeq",	"impExpDomesticClsCd",	"transCargoClsCd",	"cntrSizCd",	"cntrTypCd",	"fullEmptyClsCd",	"confirmDt",	"bankAcntNoInscrpYn",	"summary",	"spplyAmt",	"spplyAmtFcrc",	"vatAmt",	"totAmt",	"upperCertiNo",	"offsetUpperCertiNo",	"fmlaClsCd",	"fmlaPatternCd",	"crcCd",	"pldgMgntNo",	"billTitleNm",	"dcsnClsCd",	"inscrpVsslCd",	"inscrpFmlaClsCd",	"inscrpFmlaPatternCd",	"certiCnt",	"bilgAmt",	"fcrcBilgAmt",	"bilgAmtFcrc",	"wcrcDcsnClsCd",	"ediSndReqDt",	"ediSndTrgtYn",	"ediSndClsCd",	"dcsnClsCdNm",	"offsetVatNo",	"fireInsrRateAmt",	"certiCreatYn"]

    if (scwin.param.ds_certiCommon != undefined) {
        ds_certiCommonDs.setJSON(scwin.param.ds_certiCommon.getAllJSON());
    }

    if(scwin.param.sellItemNm == "") {
        scwin.hid_summary = ds_certiCommonDs.getCellData(0, "summary");
    } else {
        scwin.hid_summary = scwin.param.sellItemNm;

    }

    ds_certiCommonDs.setCellData(0, "pgmId", "fs_202_03_02b.jsp");

    //조회
    scwin.hid_goods = scwin.param.sellItemNm;

    //Radio Value	- 청구/영수
    ds_certiCommonDs.setCellData(0, "receptClsCd", "02");

    if (scwin.blno != "") {
        ed_summary.setValue(scwin.blno);
    }

    ica_slipCloseYm.setDisabled(true);
    ica_taxCloseYm.setDisabled(true);
    ed_collMoneyAcctDeptCd.setDisabled(true);
    acb_susRecvInitamtClsCd.setDisabled(true);
    cbx_sumCheck.setValue("1");

    scwin.offsetNo1 = ds_certiCommonDs.getCellData(0, "offsetNo1");

    scwin.f_Retrieve();
};


