//-------------------------------------------------------------------------
// 화면종료시
//-------------------------------------------------------------------------
scwin.btn_onUnload_onClick = async function (e) {
    let arrRtnVal = [];

    arrRtnVal[0] = ds_evidenceDs.getCellData(0, "sellVatNo");
    arrRtnVal[1] = scwin.saveflag;

    $c.win.closePopup(arrRtnVal);
};



//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회서브미션 완료시
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitDone = function (e) {

    ed_sellVatNo.setValue(ds_evidenceDs.getCellData(0, "sellVatNo"));
    ed_certiNo.setValue(ds_evidenceDs.getCellData(0, "certiNo"));					//거래명세서번호
    ed_crn.setValue(ds_evidenceDs.getCellData(0, "crn"));								//사업자번호
    ed_TEXT6.setValue(ds_evidenceDs.getCellData(0, "busiNm"));							//상호
    ed_repstNm.setValue(ds_evidenceDs.getCellData(0, "repstNm"));	                    //대표자
    ica_spplyDt.setValue(ds_evidenceDs.getCellData(0, "spplyDt"));						//공급일자	
    ed_taxnClsCd.setValue(ds_evidenceDs.getCellData(0, "taxnClsCd") + "(" + ds_evidenceDs.getCellData(0, "taxnClsNm") + ")");					//부가세구분
    ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptCd"));	//수금부서 코드
    ed_collMoneyAcctDeptNm.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptNm"));	//수금부서 명
    ed_bilgClnt.setValue(ds_evidenceDs.getCellData(0, "bilgClntNo"))//거래처
    ed_bilgClntNm.setValue(ds_evidenceDs.getCellData(0, "bilgClntNm"))	//거래처
    ed_bilgLodept.setValue(ds_evidenceDs.getCellData(0, "bilgLodeptCd") + " " + ds_evidenceDs.getCellData(0, "bilgLobranNm"));	//청구부서
    ed_slipNo.setValue(ds_evidenceDs.getCellData(0, "slipNo"));							//전표번호
    ica_slipDt.setValue(ds_evidenceDs.getCellData(0, "slipDt"));						//전표생성일자

    if (ds_evidenceDs.getCellData(0, "receptClsCd") == "") {
        rd_receptClsCd.setValue("02");					//청구/영수
    } else {
        rd_receptClsCd.setValue(ds_evidenceDs.getCellData(0, "receptClsCd"));					//청구/영수
    }

    ed_adptExchRt.setValue(ds_evidenceDs.getCellData(0, "adptExchRt"));					//환율
    ed_spplyAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "spplyAmt")));						//원화공급액
    ed_spplyAmtFcrc.setValue(ds_evidenceDs.getCellData(0, "spplyAmtFcrc"));				//외화매출액
    ed_vatAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "vatAmt")));							//부가세
    ed_fireInsrRateAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "fireInsrRateAmt")));		//화재보험표	

    if (ds_evidenceDs.getCellData(0, "sellVatNo") != "" && ds_evidenceDs.getCellData(0, "sellVatNo").length > 1) {//세금계산서 생성여부
        ed_summary.setValue(ds_evidenceDs.getCellData(0, "summary")); //저장된 적요		
    } else { //적요에 파라미터로 넘어온 BL번호 기재		
        if (scwin.blno != "") {
            ed_summary.setValue(scwin.blno);
            if (scwin.summary != "") {
                ed_summary.setValue(scwin.blno + scwin.summary);
            }
        }
    }

    ed_goods.setValue(ds_evidenceDs.getCellData(0, "goods"));							//적요
    ed_sumAmt.setValue(ds_evidenceDs.getCellData(0, "sumAmt"));   //화재보험표

    scwin.txt_sumAmtAll = Number(ds_evidenceDs.getCellData(0, "sumAmt")) + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
    scwin.sumAmtAll = Number(ds_evidenceDs.getCellData(0, "sumAmt")) + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
    acb_susRecvInitamtClsCd.setValue(ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd"));		//선/가수금구분코드
    scwin.susRecvInitamtClsCd = ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd");

    ed_cashSellAmt.setValue(ds_evidenceDs.getCellData(0, "cashSellAmt"));					//현금매출금액
    ed_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(Number(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellAmt"))));		//무통장입금
    ed_sumAmtDtl.setValue($c.gus.cfInsertComma(Number(ds_evidenceDs.getCellData(0, "cashSellAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt")) + Number(ds_evidenceDs.getCellData(0, "susRecvSellAmt")) + Number(ds_evidenceDs.getCellData(0, "pldgAmt"))));
    ed_cashRtnAmt.setValue(ds_evidenceDs.getCellData(0, "cashRtnAmt"));

    ed_offsetVatNo.setValue(ds_evidenceDs.getCellData(0, "offsetVatNo"));
    ed_offsetNo.setValue(ds_evidenceDs.getCellData(0, "offsetNo"));
    ed_dcsnClsNm.setValue(ds_evidenceDs.getCellData(0, "dcsnClsNm"));
    ica_slipCloseYm.setValue(ds_evidenceDs.getCellData(0, "slipCloseYm"));				//회계마감월
    ica_taxCloseYm.setValue(ds_evidenceDs.getCellData(0, "taxCloseYm"));					//세무마감월

    //전자세금계산서 부분
    //ed_email.text  = ds_evidenceDs.getCellData(0, "email");
    //chb_declarExceptYn.checked = ds_evidenceDs.getCellData(0, "declarExceptYn"); 
    //f_mandatoryCheck();

    let bilgAmt = 0;
    let bilgAmtFcrc = 0;
    let fcrcBilgAmt = 0;

    for (i = 0; i < ds_ctrt.getTotalRow() + 1; i++) {
        scwin.bilgAmt += Number(ds_ctrt.getCellData(i, "bilgAmt"));
        scwin.bilgAmtFcrc += Number(ds_ctrt.getCellData(i, "bilgAmtFcrc"));
        scwin.fcrcBilgAmt += Number(ds_ctrt.getCellData(i, "fcrcBilgAmt"));
    }

    scwin.bilgAmt = scwin.bilgAmt + Number(ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
    ed_bilgAmt.setValue(scwin.bilgAmt);

    if ((ds_evidenceDs.getCellData(0, "slipNo") == "")) {

        if (scwin.blno != "") {
            ed_summary.setValue(scwin.blno);
            if (scwin.summary != "") {
                ed_summary.setValue(scwin.blno + scwin.summary);
            }

        } else {

            if (ds_evidenceDs.getCellData(0, "bilgClntNo") == '310617' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310618' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310619' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '294268') { // 한화큐셀 ,현대에너지솔루션 일 경우 BL번호 세팅

                ed_summary.setValue(ds_certiCommonDs.getCellData(0, "blNo"));

            } else if (ds_evidenceDs.getCellData(0, "fmlaPatternCd") == "05") { //거래명세서유형 : 수입통관운송			
                ed_summary.setValue(scwin.hid_summary + "(" + ds_certiCommonDs.getCellData(0, "blNo") + ")");	//매출항목(blNo)
            } else {
                ed_summary.setValue(scwin.hid_summary);	//매출항목
            }
        }
        if (ds_evidenceDs.getCellData(0, "bilgClntNo") == '310617' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310618' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '310619' || ds_evidenceDs.getCellData(0, "bilgClntNo") == '294268') { // 한화큐셀,현대에너지솔루션  일 경우 매출항목  세팅

            ed_goods.setValue(scwin.hid_goods);

        } else if (ds_evidenceDs.getCellData(0, "fmlaPatternCd") == "05") { //거래명세서유형 : 수입통관운송
            ed_goods.setValue(ed_summary.getValue());	//매출항목(blNo)
        } else {
            ed_goods.setValue(scwin.hid_goods);	//매출항목
        }

        ica_spplyDt.setValue(scwin.strCurDate);
        if (scwin.intendDt != "") {
            ica_spplyDt.setValue(scwin.intendDt);
        }
        ica_slipDt.setValue(scwin.strCurDate);
    } else {
        rd_receptClsCd.setDisabled(true);
    }

    scwin.f_ButtonEnable();
};




//-------------------------------------------------------------------------
// 저장 서브미션 완료 후
//-------------------------------------------------------------------------
scwin.sbm_master_submitDone = async function (e) {
    try {
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        await $c.win.alert(MSG_CM_INF_001);
        scwin.saveflag = "TRUE";


        ed_sellVatNo.setValue(ds_evidenceDs.getCellData(0, "sellVatNo"));					//세금계산서번호
        ed_certiNo.setValue(ds_evidenceDs.getCellData(0, "certiNo"));					//거래명세서번호
        ed_crn.setValue(ds_evidenceDs.getCellData(0, "crn"));								//사업자번호
        ed_TEXT6.setValue(ds_evidenceDs.getCellData(0, "busiNm"));							//상호
        ed_repstNm.setValue(ds_evidenceDs.getCellData(0, "repstNm"));						//대표자
        ed_repstNm.setValue(ds_evidenceDs.getCellData(0, "spplyDt"));						//공급일자
        ed_taxnClsCd.setValue(ds_evidenceDs.getCellData(0, "taxnClsCd") + " (" + ds_evidenceDs.getCellData(0, "taxnClsNm") + ")");					//부가세구분
        ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptCd"));	//수금부서 코드
        ed_bilgClnt.setValue(ds_evidenceDs.getCellData(0, "collMoneyAcctDeptNm"));	//수금부서 명
        ed_bilgClnt.setValue(ds_evidenceDs.getCellData(0, "bilgClntNo")); //거래처
        ed_bilgClntNm.setValue(ds_evidenceDs.getCellData(0, "bilgClntNm"));	//거래처
        ed_bilgLodept.setValue(ds_evidenceDs.getCellData(0, "bilgLodeptCd") + " " + ds_evidenceDs.getCellData(0, "bilgLobranNm"));	//청구부서
        ed_slipNo.setValue(ds_evidenceDs.getCellData(0, "slipNo"));							//전표번호
        ica_slipDt.setValue(ds_evidenceDs.getCellData(0, "slipDt"));						//전표생성일자
        rd_receptClsCd.setValue(ds_evidenceDs.getCellData(0, "receptClsCd"));					//청구/영수
        ed_adptExchRt.setValue(ds_evidenceDs.getCellData(0, "adptExchRt"));					//환율
        ed_spplyAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "spplyAmt")));						//원화공급액
        ed_spplyAmtFcrc.setValue(ds_evidenceDs.getCellData(0, "spplyAmtFcrc"));				//외화매출액
        ed_vatAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "vatAmt")));							//부가세
        ed_fireInsrRateAmt.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "fireInsrRateAmt")));		//화재보험표
        ed_summary.setValue(ds_evidenceDs.getCellData(0, "summary"));							//적요	 


        if (scwin.intendDt != "") {
            ica_spplyDt.setValue(scwin.intendDt);
        }

        ed_goods.setValue(ds_evidenceDs.getCellData(0, "goods"));							//적요
        ed_sumAmt.setValue(Number(ds_evidenceDs.getCellData(0, "sumAmt")));		//화재보험표
        ed_sumAmtAll.setValue(ds_evidenceDs.getCellData(0, "sumAmt") + ds_evidenceDs.getCellData(0, "fireInsrRateAmt"));
        scwin.sumAmtAll = ds_evidenceDs.getCellData(0, "sumAmt") + ds_evidenceDs.getCellData(0, "fireInsrRateAmt");
        acb_susRecvInitamtClsCd.getValue(ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd"));		//선/가수금구분코드
        scwin.susRecvInitamtClsCd = ds_evidenceDs.getCellData(0, "susRecvInitamtClsCd");

        ed_bilgAmt.setValue(ds_evidenceDs.getCellData(0, "bilgAmt"));
        ed_cashSellAmt.text = ds_evidenceDs.getCellData(0, "cashSellAmt");					//현금매출금액
        ed_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt") + ds_evidenceDs.getCellData(0, "susRecvSellAmt")));		//무통장입금
        ed_sumAmtDtl.setValue($c.gus.cfInsertComma(ds_evidenceDs.getCellData(0, "cashSellAmt") + ds_evidenceDs.getCellData(0, "susRecvSellRtnDrAmt") + ds_evidenceDs.getCellData(0, "susRecvSellAmt") + ds_evidenceDs.getCellData(0, "pldgAmt")));
        ed_cashRtnAmt.setValue(ds_evidenceDs.getCellData(0, "cashRtnAmt"));

        ed_slipCloseYm.setValue(ds_evidenceDs.getCellData(0, "slipCloseYm"));				//회계마감월
        ed_taxCloseYm.setValue(ds_evidenceDs.getCellData(0, "taxCloseYm"));					//세무마감월


        if (ds_evidenceDs.getCellData(0, "slipNo") == "") {
            ed_summary.setValue(scwin.hid_summary);	//매출항목	
            ed_goods.setValue(scwin.hid_goods);	//매출항목	
        } else {
            rd_receptClsCd.setDisabled(true);
        }

        if (ds_evidenceDs.getCellData(0, "hitekSendYn") == "Y") {
            $c.win.alert("동부 하이텍에 전송된  기존 운임정보가 존재합니다.");
        }

    } catch (e) {
        console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

    scwin.f_ButtonEnable();
};

//-------------------------------------------------------------------------
// Button Enable/ Disable
//-------------------------------------------------------------------------
scwin.f_ButtonEnable = function () {
    //세금계산서 생성여부

    if (ds_evidenceDs.getCellData(0, "sellVatNo") != null && ds_evidenceDs.getCellData(0, "sellVatNo").length > 1) {
        btn_save.setDisabled(true);
        btn_delete.setDisabled(false);
    } else {
        btn_save.setDisabled(false);
        btn_delete.setDisabled(true);
    }
};


//-------------------------------------------------------------------------
// 저장 f_save
//-------------------------------------------------------------------------
scwin.btn_save_onClick = async function () {

    // 청구 / 영수가 청구일 경우에만 관리거래처 체크
    if (rd_receptClsCd.getValue() == "02") {
        await scwin.f_retrieveCtrtNo2();

        if (scwin.clntMgntYn == 1) {
            return;
        }
    }

    // 청구일  경우 매출입구분이 영수매출인 경우는 세금계산서 생성 불가 2011.06.22
    if (rd_receptClsCd.getValue() == "02") {
        if (ds_evidenceDs.getCellData(0, "receiveSellingYn") == "1") {
            await $c.win.alert("청구할 수 없는 영수매출 거래처입니다.<br>다시 확인하십시오!");
            return;
        }
    }

    // 가수금인 경우 가수금의 입금일자가 전표일자보다 크면 세금계산서 생성 불가 2016.12.12
    let chkSlipMm = ica_slipDt.getValue().substring(0, 6);
    let chkSusMn = "";
    if (ds_collMoney.getTotalRow() > 0) {
        for (i = 0; i < ds_collMoney.getTotalRow(); i++) {
            chkSusMn = ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6);
            if (chkSusMn > chkSlipMm) {
                await $c.win.alert("가수금의 입금월은 전표월보다 이전이거나 같아야 합니다. <br>다시 확인하십시오.");
                return;
            }
        }
    }

    //필수입력항목 체크
    if (rd_receptClsCd.getValue() == "01") {
        ds_evidenceDs.setCellData(0, "collMoneyAcctDeptCd", ds_evidenceDs.getCellData(0, "acctDeptCd"));
        ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "acctDeptCd"));
    } else {
        if (ed_collMoneyAcctDeptCd.getValue() == null) {
            ed_collMoneyAcctDeptCd.setValue(ds_evidenceDs.getCellData(0, "acctDeptCd"));
        }
    }

    ds_evidenceDs.setCellData(0, "collMoneyAcctDeptCd", ed_collMoneyAcctDeptCd.getValue());
    //공급일자, 전표일자, 수금부서, 적요(비고), 품명
    if (! await $c.gus.cfValidate([ica_spplyDt, ica_slipDt, ed_collMoneyAcctDeptCd, ed_summary, ed_goods])) return;

    ds_evidenceDs.setCellData(0, "fmlaClsCd", "01");	//거래명세서 : 01, Bill : 02
    ds_evidenceDs.setCellData(0, "evidRglClsCd", "01");	//세금계산서 상태 : 01 '정상', 02 '적자', 99 '삭제'
    ds_evidenceDs.setCellData(0, "spplyDt", ica_spplyDt.getValue());
    ds_evidenceDs.setCellData(0, "slipDt", ica_slipDt.getValue());
    ds_evidenceDs.setCellData(0, "summary", ed_summary.getValue());	//적요
    ds_evidenceDs.setCellData(0, "goods", ed_goods.getValue());	//적요
    ds_evidenceDs.setCellData(0, "receptClsCd", rd_receptClsCd.getValue());		// 영수/청구
    ds_evidenceDs.setCellData(0, "chk", ds_ctrt.getCellData(0, "sellLodeptCd"));


    //청구귀속부서가 국제영업1팀 (1G34), 국제영업3팀( 1G36)인경우 공급일자와 전표일자의  월(月) 이 상이하게 저장  될 시 오류 메시지 표시
    if (ds_evidenceDs.getCellData(0, "bilgLodeptCd") == "1G34" || ds_evidenceDs.getCellData(0, "bilgLodeptCd") == "1G36") {
        let chkSlipDt = ica_slipDt.getValue().substring(0, 6);
        let chkSpplyDt = ica_spplyDt.getValue().substring(0, 6);
        if ((ica_slipDt.getValue() != "" && ica_spplyDt.getValue() != "") && (chkSlipDt != chkSpplyDt)) {
            if (!await $c.win.confirm("공급월과 전표투입월이 일치하지 않습니다. 저장 하시겠습니까?")) {
                return;
            }
        }
    }

    if (rd_receptClsCd.getValue() == "01") {
        //수금 내역 금액 검증
        if (! await scwin.f_chkAmt()) {
            $c.win.alert("수금정보의 금액항목 오류입니다. <br>다시 확인하십시오.");
            return;
        }
        //환불(전도금-현금)계정이 발생하면 에러처리 2011.07.01
        if (ed_cashRtnAmt.getValue() != 0) {
            $c.win.alert("전도금계정 전표는 생성할 수 없습니다.<br>다시 확인하십시오.");
            return;
        }
        if (! await $c.win.confirm((MSG_CM_CRM_001))) {
            return;
        }

        ds_evidenceDs.setCellData(0, "cashSellAmt", ed_cashSellAmt.getValue());
        ds_evidenceDs.setCellData(0, "susRecvSellRtnDrAmt", scwin.susRecvSellRtnDrAmt);
        ds_evidenceDs.setCellData(0, "susRecvSellAmt", scwin.susRecvSellAmt);
        ds_evidenceDs.setCellData(0, "cashRtnAmt", ed_cashRtnAmt.getValue());
        ds_evidenceDs.setCellData(0, "susRecvInitamtClsCd", acb_susRecvInitamtClsCd.getValue());

    } else {
        if (! await $c.win.confirm(MSG_CM_CRM_001)) {
            return;
        }

        ds_evidenceDs.setCellData(0, "bilgAmt", scwin.bilgAmt);
        ds_evidenceDs.setCellData(0, "bilgAmtFcrc", scwin.bilgAmtFcrc);
        ds_evidenceDs.setCellData(0, "fcrcBilgAmt", scwin.fcrcBilgAmt);
    }

    //전자세금계산서 조회를 위한 URL 생성
    let locPtnCls = scwin.locPtnCls;  // 1.Invoice, 2.Partner
    let seaair = scwin.seaair;
    if (seaair != "") {
        if (locPtnCls == "1") {
            if (seaair == "S") {
                let url = scwin.f_createUrl("/il/acc/ac_101_01_01_sea.ozr", "ac_101_01_01_sea.odi", scwin.f_createParameter());
                ds_certiCommonDs.setCellData(0, "url", url);
            } else {
                let url = scwin.f_createUrl("/il/acc/ac_101_01_01_air.ozr", "ac_101_01_01_air.odi", scwin.f_createParameter());
                ds_certiCommonDs.setCellData(0, "url", url);
            }
        } else {
            let url = scwin.f_createUrl("/il/acc/ac_104_01_01.ozr", "ac_104_01_01.odi", scwin.f_createPartnerParam());
            ds_certiCommonDs.setCellData(0, "url", url);
        }
    } else {
        let odi1 = "01";
        let odi2 = ds_certiCommonDs.getCellData(0, "inscrpFmlaPatternCd");

        let url = scwin.f_createUrl("/ds/fs/fs_202_06_10_" + odi1 + "_" + odi2 + ".ozr", "fs_202_06_10_" + odi1 + "_" + odi2 + ".odi", scwin.f_createParam());
        ds_certiCommonDs.setCellData(0, "url", url);
    }

    var features = "copyHeader=yes";
    //Insert를 위해서 DataSet 복사 : ds_evidenceDs -> ds_evidenceContDs
    $c.gus.cfCopyDataSet(ds_evidenceDs, ds_evidenceContDs, features);


    $c.sbm.execute(sbm_master);

    scwin.f_ButtonEnable();
};




//-------------------------------------------------------------------------
// 전자세금계산서 발행시 보여질 레포트 URL 생성
// 예)
// ozrFileNm = "/ds/fs/fs_202_06_10_01_02.ozr"
// odiFileNm = "fs_202_06_10_01_02.odi"
// ozParam = "bilgLodeptCd=6A1,qryConKnd=2,...";
// URL이 최대 1000자가 넘어선 안된다.
//-------------------------------------------------------------------------
scwin.f_createUrl = function (ozrFileNm, odiFileNm, ozParam) {
    let url = "";

    url = "http://ebiz.debis.co.kr/common/jsp/external_interface.jsp?"
        + "SYS_CD=OSIDE_CERTI&certiOzrFileNm=" + ozrFileNm
        + "&certiOdiFileNm=" + odiFileNm
        + "&certiOzParam=" + ozParam;

    return url;
};

//-------------------------------------------------------------------------
// 전자세금계산서 발행시 보여질 레포트 PARAMETER 생성 --> <<국제물류>>
//-------------------------------------------------------------------------
scwin.f_createParameter = function () {
    let param = "";

    param = "KCOMCD=" + scwin.kcomcd
        + ",PRTN_GRP_NO=" + scwin.prtnGrpNo
        + ",SEAAIR=" + scwin.seaair
        + ",IOGB=" + scwin.iogb
        + ",BILG_CLNT_NO=" + scwin.bilgClntNo
        + ",USER_ID=" + scwin.userId
        + ",TYPE=" + scwin.type
        + ",RMK=" + scwin.rmk
        + ",REMARK=" + scwin.remark
        + ",ENG=" + scwin.eng
        + ",PIC=" + scwin.pic;

    return param;
};


//-------------------------------------------------------------------------
// 전자세금계산서 발행시 보여질 레포트 PARAMETER 생성 --> <<국제물류-파트너 Invoice>>
//-------------------------------------------------------------------------
scwin.f_createPartnerParam = function () {
    let param = "";

    param = "KCOMCD=" + scwin.kcomcd
        + ",PRTN_GRP_NO=" + scwin.prtnGrpNo
        + ",SEAAIR=" + scwin.seaair
        + ",IOGB=" + scwin.iogb
        + ",BILG_CLNT_NO=" + scwin.bilgClntNo
        + ",USER_ID=" + scwin.userId
        + ",TYPE=" + scwin.type
        + ",PIC=" + scwin.pic;

    return param;
};



//-------------------------------------------------------------------------
// 전자세금계산서 발행시 보여질 레포트 PARAM 생성
//-------------------------------------------------------------------------
scwin.f_createParam = function () {
    let param = "";

    param = "bilgLodeptCd=" + ds_certiCommonDs.getCellData(0, "bilgLodeptCd")
        + ",bilgClntNo=" + ds_certiCommonDs.getCellData(0, "bilgClntNo")
        + ",qryConKnd=" + "02"
        + ",confirmDtFm=" + ""
        + ",confirmDtTo=" + ""
        + ",spplyDtFm=" + ""
        + ",spplyDtTo=" + ""
        + ",modId=" + ""
        + ",printFg=" + ""
        + ",certiAggregateFg=" + ""
        + ",dcsnClsCd=" + ""
        + ",certiNo=" + ds_certiCommonDs.getCellData(0, "certiNo")
        + ",fmlaClsCd=" + ds_certiCommonDs.getCellData(0, "fmlaClsCd")
        + ",fmlaPatternCd=" + ds_certiCommonDs.getCellData(0, "fmlaPatternCd")
        + ",upperFmlaClsCd=" + ""
        + ",upperFmlaPatternCd=" + ""
        + ",sellVatNo=" + ""
        + ",inscrpFmlaClsCd=" + ds_certiCommonDs.getCellData(0, "inscrpFmlaClsCd")
        + ",inscrpFmlaPatternCd=" + ds_certiCommonDs.getCellData(0, "inscrpFmlaPatternCd")
        + ",spplyFg=" + acb_spplyFg.getValue()
        + ",ozNo=" + acb_ozNo.getValue()
        + ",sumGbn=" + (cbx_sumCheck.getValue() == "1" ? "Y" : "N")
        + ",wtGbn=" + (cbx_wt.getValue() == "1" ? "Y" : "N");

    return param;
};




//-------------------------------------------------------------------------
// 금액계산 입력시 검증
//-------------------------------------------------------------------------
scwin.f_chkAmt = async function () {
    await scwin.f_setMethAmt();

    if (scwin.sumAmtAll == scwin.cashSellAmt + scwin.susRecvSellRtnDrAmt + scwin.susRecvSellAmt - ((scwin.susRecvSellRtnDrAmt + scwin.cashRtnAmt) / 2)) {
        return true;
    } else {
        return false;
    }
};


//-------------------------------------------------------------------------
// 관리 거래처 체크
//-------------------------------------------------------------------------
scwin.f_retrieveCtrtNo2 = async function () {

    if (dma_cndCtrtNo.get("ctrtClntNo") != null || dma_cndCtrtNo.get("ctrtClntNo") != "") {
        dma_cndCtrtNo.set("ctrtClntNo", "");
    } 

    //검색조건값 세팅
    dma_cndCtrtNo.set("ctrtClntNo", ed_bilgClnt.getValue());	//거래처 코드 

    //조회
    await $c.sbm.execute(sbm_retrieveCtrtNo2);
    await scwin.sbm_retrieveCtrtNo2_submitdone();
};

//-------------------------------------------------------------------------
// 삭제 
//-------------------------------------------------------------------------
scwin.btn_delete_onClick = async function () {

    if (! await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008, "세금계산서(" + ds_evidenceDs.getCellData(0, "sellVatNo") + ")"))) {
        return;
    }

    if (scwin.offsetNo1 != "") {
        $c.win.alert("역분개된 세금계산서입니다. 거래명세서번호에 'A01'을 붙인 거래명세서번호로 조회하여 작업하십시오.<br><br>(예: 거래명세서번호가 'V500068317'인 경우 'V500068317A01'조회)");
        return;
    }

    ds_evidenceDs.setCellData(0, "fmlaClsCd", "01");	//거래명세서 : 01, Bill : 02

    if (ds_evidenceDs.getCellData(0, "postDt").substring(0, 6) <= ica_slipCloseYm.getValue() && ds_evidenceDs.getCellData(0, "postDt").trim() != "") {
        let msg = "마감완료된 전표 이므로  역전표 생성 됩니다. 마감기간일 경우 마감이 완전히 끝났는지 확인하시고, 작업하십시요!";
        if (! await $c.win.confirm(msg)) {
            return;
        }
    }

    if (ds_evidenceDs.getCellData(0, "hitekSendYn") == "Y") {
        let msg = "동부 하이텍에 전송된 운임정보가 있습니다..<br><br>계속 작업하시겠습니까 ?";
        if (! await $c.win.confirm(msg)) {
            return;
        }
    }

    if (! await scwin.f_CheckTaxCancelSpplyDt()) {
        return;
    }


    ds_evidenceDs.setCellData(0, "cancelSpplyDt", ica_cancelSpplyDt.getValue());

    if (ds_evidenceDs.getCellData(0, "receptClsCd") == '02') {
        $c.sbm.execute(sbm_DeleteCerti2)
    } else if (ds_evidenceDs.getCellData(0, "receptClsCd") == '01') {
        $c.sbm.execute(sbm_DeleteCerti1)
    }

    scwin.f_ButtonEnable();
};

