        scwin.saveflag = "TRUE";
        scwin.btn_onUnload_onClick();
        // scwin.f_ButtonEnable.();
    } catch (e) {
        console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }
};

scwin.sbm_DeleteCerti1_submitDone = async function (e) {
    try {
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        await $c.win.alert(MSG_CM_INF_004);
        scwin.isDelete = true;
        scwin.saveflag = "TRUE";
        scwin.btn_onUnload_onClick();
        // scwin.f_ButtonEnable();
    } catch (e) {
        console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }
};


//-------------------------------------------------------------------------
// 세금계산서 취소 때  세무마감여부 CHECK
//-------------------------------------------------------------------------
scwin.f_CheckTaxCancelSpplyDt = async function () {
    let taxCloseYm = ica_taxCloseYm.getValue();
    let spplyYm = ica_spplyDt.getValue().substring(0, 6);
    let isTrue;

    if (taxCloseYm >= spplyYm) {
        isTrue = $c.win.confirm("세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)<br><br>세금계산서 및 전표를 취소하시겠습니까?")

        if (!isTrue) {
            return;
        }

        if (ica_cancelSpplyDt.getValue() == null || ica_cancelSpplyDt.getValue() == "") {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "[수정세금계산서 공급일자 ]")); //@은(는) 필수 입력 항목입니다
            ica_cancelSpplyDt.focus();
            return false;
        }
        if (! await $c.gus.cfValidate([ica_cancelSpplyDt])) {
            ica_cancelSpplyDt.focus;
            return;
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 가수금 내역 팝업창 처리 f_susRecvPop
//-------------------------------------------------------------------------
scwin.btn_susRecvPop_onClick = async function () {

    if (rd_receptClsCd.getValue() != "01") {
        // $c.win.alert("영수 세금계산서 생성시만 가수금 계정을 책정할 수 있습니다.");
        $c.win.alert("영수 세금계산서 생성시만 가수금 계정을 책정할 수 있습니다.")
        return;
    }

    scwin.txt_susRecvSellAmtTot = 0;
    ed_susRecvSellAmtTot.setValue("0");

    await scwin.f_setAmtSusRecvSellAmtTot();

    ds_collMoney.removeAll();

    let valueObject = {
        "prov": ds_collMoney,
        "fromDate": scwin.strFrDate,
        "toDate": scwin.strCurDate,
        "clsCd": acb_susRecvInitamtClsCd.getValue() == "01" ? "2" : "3",	// 1:가수금/선수금, 2:가수금, 3:선수금
        "clntNo": ed_bilgClnt.getValue(),
        "bankbookNo": ""		//통장번호 -> 필요없을경우 Setting 안해도됨.;
    }

    // 팝업 옵션 설정
    let options = {
        id: "taxPop",
        popupName: "가수금/선수금POPUP화면",
        width: 1100,
        height: 650
    };

    //상세화면 호출
    let returnValue = await $c.win.openPopup("/ui/ac/fm/collmoneymgnt/rcptmgnt/fm_502_03_00p.xml", options, valueObject);
    let remainAmt = 0;

    for (i = 0; i < ds_collMoney.getTotalRow(); i++) {
        remainAmt += Number(ds_collMoney.getCellData(i, "remainAmt"));
    }

    scwin.txt_susRecvSellAmtTot = remainAmt;
    //ed_susRecvSellAmtTot.getStyleValue(remainAmt);
    ed_susRecvSellAmtTot.setValue($c.gus.cfInsertComma(remainAmt));

    await scwin.f_setAmtSusRecvSellAmtTot();
};


//-------------------------------------------------------------------------
// 금액계산 가수금액 입력시
//-------------------------------------------------------------------------
scwin.f_setAmtSusRecvSellAmtTot = async function () { 
    await scwin.f_setMethAmt();

    scwin.susRecvSellAmt = (scwin.sumAmtAll - scwin.susRecvSellAmtTot) >= 0 ? scwin.susRecvSellAmtTot : scwin.sumAmtAll;
    scwin.susRecvSellRtnDrAmt = (scwin.susRecvSellAmtTot - scwin.susRecvSellAmt);
    scwin.cashRtnAmt = scwin.susRecvSellRtnDrAmt;

    scwin.txt_susRecvSellRtnDrAmt = scwin.susRecvSellRtnDrAmt;
    scwin.txt_susRecvSellAmt = scwin.susRecvSellAmt;
    ed_cashRtnAmt.setValue(scwin.cashRtnAmt);


    ed_sumAmtDtl.setValue($c.gus.cfInsertComma(scwin.cashSellAmt + scwin.susRecvSellAmtTot));
    ed_cashSellAmtCon.setValue((scwin.sumAmtAll - scwin.susRecvSellRtnDrAmt - scwin.susRecvSellAmt + scwin.cashRtnAmt));
};

//-------------------------------------------------------------------------
// 금액계산
//-------------------------------------------------------------------------
scwin.f_setMethAmt = async function () {

    scwin.sumAmtAll = scwin.txt_sumAmtAll;
    scwin.cashSellAmt = ed_cashSellAmt.getValue();
    scwin.susRecvSellRtnDrAmt = scwin.txt_susRecvSellRtnDrAmt;
    scwin.susRecvSellAmt = scwin.txt_susRecvSellAmt;
    scwin.susRecvSellAmtTot = scwin.txt_susRecvSellAmtTot;
    scwin.cashRtnAmt = ed_cashRtnAmt.getValue();

    scwin.sumAmtAll = Number(scwin.sumAmtAll);
    scwin.cashSellAmt = Number(scwin.cashSellAmt);
    scwin.susRecvSellRtnDrAmt = Number(scwin.susRecvSellRtnDrAmt);
    scwin.susRecvSellAmt = Number(scwin.susRecvSellAmt);
    scwin.susRecvSellAmtTot = Number(scwin.susRecvSellAmtTot);
    scwin.cashRtnAmt = Number(scwin.cashRtnAmt);
};

//-------------------------------------------------------------------------
// 금액계산 현금 매출액 입력시
//-------------------------------------------------------------------------
scwin.f_setAmtCashSellAmt = async function (e) {
    await scwin.f_setMethAmt();

    ed_sumAmtDtl.setValue(scwin.cashSellAmt + scwin.susRecvSellAmtTot)
    ed_cashSellAmtCon.setValue(scwin.sumAmtAll - scwin.susRecvSellRtnDrAmt - scwin.susRecvSellAmt + scwin.cashRtnAmt);

};

