//-------------------------------------------------------------------------
// tr_retrieveCtrtNo에서 OnSuccess이벤트 발생시
//-------------------------------------------------------------------------
scwin.sbm_retrieveCtrtNo2_submitdone = async function (e) {
    try {
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        var ctrtNoRows = ds_ctrtNo2.getTotalRow();

        if (ctrtNoRows > 0) {

            //계약번호가 서로 다른 것이 있는 경우, 선택을 default로 보여주기 위한 process
            var sameYn = "N";

            for (j = 0; j < ds_ctrtNo2.getTotalRow(); j++) {
                if ("1" == ds_ctrtNo2.getCellData(j, "mgntTrgtClntYn")) {
                    sameYn = "Y";
                    break;
                }
            }

            if (sameYn == "Y") {
                await $c.win.alert("청구처가 관리대상 거래처 입니다.<br>거래처코드의 상태를 확인하시고, 관리거래처인 경우에는 저장할 수 없습니다.");
                scwin.clntMgntYn = 1;

                return;
            } else {
                scwin.clntMgntYn = 0;
            }
        } else {
           await $c.win.alert("청구처가 관리대상 거래처 입니다.");
           return;
        }
    } catch (e) {
        console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }
};

//-------------------------------------------------------------------------
// tr_retrieveCtrtNo에서 로드되는 데이터
//-------------------------------------------------------------------------
scwin.ds_evidenceDs_ondataload = function () {
    let rowCnt = ds_evidenceDs.getTotalRow();

    if (rowCnt == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
    }
    spa_totalRow.setValue(rowCnt);
};

//-------------------------------------------------------------------------
// 청구 / 영수 라디오버튼 값 변경시
//-------------------------------------------------------------------------
scwin.rd_receptClsCd_onchange = function (info) {

    if (rd_receptClsCd.getValue() == "01") {	//영수
        ed_bilgAmt.setValue("0");
        ed_cashSellAmt.setValue("0");
        ed_susRecvSellAmtTot.setValue("0");
        scwin.txt_susRecvSellAmtTot = 0;
        scwin.txt_susRecvSellAmt = 0;
        scwin.txt_susRecvSellRtnDrAmt = 0;
        ed_sumAmtDtl.setValue("0");
        ed_cashRtnAmt.setValue(0);
        ed_cashSellAmt.setReadOnly(true);
        acb_susRecvInitamtClsCd.setDisabled(false);
        ed_cashSellAmtCon.setValue(scwin.sumAmtAll);
        ica_spplyDt.setValue(scwin.strCurDate);
        ica_slipDt.setValue(scwin.strCurDate);
    } else {									//청구
        ed_bilgAmt.setValue(scwin.bilgAmt);
        ed_cashSellAmt.setValue(0);
        ed_susRecvSellAmtTot.setValue(0);
        scwin.txt_susRecvSellAmtTot = 0;
        scwin.txt_susRecvSellAmt = 0;
        scwin.txt_susRecvSellRtnDrAmt = 0;
        ed_sumAmtDtl.setValue(0);
        ed_cashRtnAmt.setValue(0);
        ed_cashSellAmtCon.setValue(0);
        ed_cashSellAmt.setReadOnly(true);
        acb_susRecvInitamtClsCd.setDisabled(true);
        ica_slipDt.setReadOnly(false);
    }
};

//-------------------------------------------------------------------------
// 선 / 가수금 select 박스 변경시
//-------------------------------------------------------------------------
scwin.acb_susRecvInitamtClsCd_onchange = function (info) {
    if (scwin.susRecvInitamtClsCd != acb_susRecvInitamtClsCd.getValue()) {
        scwin.susRecvInitamtClsCd = acb_susRecvInitamtClsCd.getValue();
        scwin.txt_susRecvSellAmtTot = 0;
        ed_susRecvSellAmtTot.setValue(0);
        scwin.f_setAmtSusRecvSellAmtTot();
        ds_collMoney.removeAll();
    }
};
